SELECT 
FROM sys_file
WHERE del_flag = '0'

    AND folder_id = #{query.folderId}


    AND category = #{query.category}


    AND media_type = #{query.mediaType}


    AND file_name LIKE CONCAT('%', #{query.fileName}, '%')


    AND create_by LIKE CONCAT('%', #{query.createBy}, '%')


    AND create_time >= #{query.beginTime}


    AND create_time <= #{query.endTime}

ORDER BY create_time DESC

SELECT 
FROM sys_file
WHERE del_flag = '2'

    AND category = #{query.category}


    AND file_name LIKE CONCAT('%', #{query.fileName}, '%')


    AND delete_by LIKE CONCAT('%', #{query.deleteBy}, '%')


    AND delete_time >= #{query.beginTime}


    AND delete_time <= #{query.endTime}

ORDER BY delete_time DESC
